$.bm.h(0,"\u0440\u0430\u043c\u0438\u043f\u0440\u0438\u043b","\u041f\u0440\u0438 \u0421\u041a\u0424 <30 \u043c\u043b/\u043c\u0438\u043d \u2014 \u0441\u0442\u0430\u0440\u0442\u043e\u0432\u0430\u044f \u0434\u043e\u0437\u0430 1.25 \u043c\u0433 (\u043e\u0441\u043e\u0431\u0430\u044f \u043f\u043e\u043f\u0440\u0430\u0432\u043a\u0430 ESC). \u0414\u043e\u043a\u0430\u0437\u0430\u043d\u043d\u043e\u0435 \u0441\u043d\u0438\u0436\u0435\u043d\u0438\u0435 \u043e\u0431\u0449\u0435\u0439 \u0441\u043c\u0435\u0440\u0442\u043d\u043e\u0441\u0442\u0438 \u043d\u0430 16% (HOPE). \u0426\u0435\u043b\u0435\u0432\u0430\u044f \u0434\u043e\u0437\u0430 \u0434\u043b\u044f \u043a\u0430\u0440\u0434\u0438\u043e\u043f\u0440\u043e\u0442\u0435\u043a\u0446\u0438\u0438 \u2014 10 \u043c\u0433/\u0441\u0443\u0442. \u0422\u0438\u0442\u0440\u0430\u0446\u0438\u044f: \u0443\u0434\u0432\u043e\u0435\u043d\u0438\u0435 \u0434\u043e\u0437\u044b \u043a\u0430\u0436\u0434\u044b\u0435 2-4 \u043d\u0435\u0434\u0435\u043b\u0438. \u041e\u0431\u044f\u0437\u0430\u0442\u0435\u043b\u0435\u043d \u043a\u043e\u043d\u0442\u0440\u043e\u043b\u044c \u0410\u0414, \u043a\u0430\u043b\u0438\u044f, \u043a\u0440\u0435\u0430\u0442\u0438\u043d\u0438\u043d\u0430. \u0420\u0438\u0441\u043a \u0430\u043d\u0430\u0444\u0438\u043b\u0430\u043a\u0442\u043e\u0438\u0434\u043d\u044b\u0445 \u0440\u0435\u0430\u043a\u0446\u0438\u0439 \u043f\u0440\u0438 \u0434\u0438\u0430\u043b\u0438\u0437\u0435 \u0441 \u0432\u044b\u0441\u043e\u043a\u043e\u043f\u0440\u043e\u0442\u043e\u0447\u043d\u044b\u043c\u0438 \u043c\u0435\u043c\u0431\u0440\u0430\u043d\u0430\u043c\u0438.")
$.bl.h(0,"\u0444\u043e\u0437\u0438\u043d\u043e\u043f\u0440\u0438\u043b","\u041f\u0440\u043e\u043b\u0435\u043a\u0430\u0440\u0441\u0442\u0432\u043e \u0441 \u0443\u043d\u0438\u043a\u0430\u043b\u044c\u043d\u044b\u043c \u0434\u0432\u043e\u0439\u043d\u044b\u043c \u043f\u0443\u0442\u0451\u043c \u0432\u044b\u0432\u0435\u0434\u0435\u043d\u0438\u044f: \u043f\u043e\u0447\u043a\u0438 (50%) + \u043f\u0435\u0447\u0435\u043d\u044c (50%). \u0412 \u043f\u0435\u0447\u0435\u043d\u0438 \u0433\u0438\u0434\u0440\u043e\u043b\u0438\u0437\u0443\u0435\u0442\u0441\u044f \u0434\u043e \u0444\u043e\u0437\u0438\u043d\u043e\u043f\u0440\u0438\u043b\u0430\u0442\u0430 \u2014 \u0430\u043a\u0442\u0438\u0432\u043d\u043e\u0433\u043e \u0438\u043d\u0433\u0438\u0431\u0438\u0442\u043e\u0440\u0430 \u0410\u041f\u0424. \u041f\u0440\u0438 \u043f\u043e\u0447\u0435\u0447\u043d\u043e\u0439 \u043d\u0435\u0434\u043e\u0441\u0442\u0430\u0442\u043e\u0447\u043d\u043e\u0441\u0442\u0438 \u0430\u0432\u0442\u043e\u043c\u0430\u0442\u0438\u0447\u0435\u0441\u043a\u0438 \u0443\u0432\u0435\u043b\u0438\u0447\u0438\u0432\u0430\u0435\u0442\u0441\u044f \u043f\u0435\u0447\u0451\u043d\u043e\u0447\u043d\u0430\u044f \u044d\u043b\u0438\u043c\u0438\u043d\u0430\u0446\u0438\u044f, \u0447\u0442\u043e \u043f\u043e\u0437\u0432\u043e\u043b\u044f\u0435\u0442 \u043d\u0435 \u043a\u043e\u0440\u0440\u0435\u043a\u0442\u0438\u0440\u043e\u0432\u0430\u0442\u044c \u0434\u043e\u0437\u0443 \u043f\u0440\u0438 \u0425\u041f\u041d. \u0421\u043e\u0434\u0435\u0440\u0436\u0438\u0442 \u0444\u043e\u0441\u0444\u0438\u043d\u0438\u043b\u044c\u043d\u0443\u044e (\u0430 \u043d\u0435 \u0441\u0443\u043b\u044c\u0444\u0433\u0438\u0434\u0440\u0438\u043b\u044c\u043d\u0443\u044e) \u0433\u0440\u0443\u043f\u043f\u0443, \u0447\u0442\u043e \u0441\u043d\u0438\u0436\u0430\u0435\u0442 \u0440\u0438\u0441\u043a \u043a\u043e\u0436\u043d\u044b\u0445 \u0440\u0435\u0430\u043a\u0446\u0438\u0439 \u0438 \u043d\u0430\u0440\u0443\u0448\u0435\u043d\u0438\u044f \u0432\u043a\u0443\u0441\u0430.")
